  \draw[pattern=north east lines,pattern color=gray!70] (-0.5,-0.35) rectangle (6.6,0);
  \draw[thick] (-0.5,0)--(6.6,0);
  \coordinate (L) at (1.4,3);
  \fill (L) circle (2pt);
